var item = $input.item.json;

// Gmail Trigger can use UPPERCASE or lowercase field names
// Check both formats

// --- SENDER ---
var sender = "unknown";
var senderName = "";

if (item.From) {
  var fromStr = item.From;
  var emailMatch = fromStr.match(/<([^>]+)>/);
  if (emailMatch) {
    sender = emailMatch[1];
  } else {
    sender = fromStr;
  }
  var nameMatch = fromStr.match(/^([^<]+)</);
  if (nameMatch) {
    senderName = nameMatch[1].trim();
  }
} else if (item.from && typeof item.from === "object" && item.from.value && item.from.value[0]) {
  sender = item.from.value[0].address || "unknown";
  senderName = item.from.value[0].name || "";
} else if (item.from && typeof item.from === "string") {
  sender = item.from;
}

// --- SUBJECT ---
var subject = item.Subject || item.subject || "(no subject)";

// --- BODY ---
var body = "";

if (item.textPlain) {
  body = item.textPlain;
} else if (item.text) {
  body = item.text;
} else if (item.snippet) {
  body = item.snippet;
} else if (item.textHtml) {
  var html = item.textHtml;
  html = html.replace(/<[^>]+>/g, " ");
  html = html.replace(/&nbsp;/g, " ");
  html = html.replace(/&amp;/g, "&");
  html = html.replace(/&lt;/g, "<");
  html = html.replace(/&gt;/g, ">");
  html = html.replace(/&#39;/g, "'");
  body = html.replace(/\s+/g, " ").trim();
}

if (body.length > 3000) {
  body = body.substring(0, 3000);
}

// --- SKIP BOUNCE EMAILS ---
var senderLower = sender.toLowerCase();
var subjectLower = subject.toLowerCase();

var isBounce = false;
if (senderLower.indexOf("mailer-daemon") !== -1) { isBounce = true; }
if (senderLower.indexOf("postmaster") !== -1) { isBounce = true; }
if (subjectLower.indexOf("delivery status") !== -1) { isBounce = true; }
if (subjectLower.indexOf("undeliverable") !== -1) { isBounce = true; }
if (subjectLower.indexOf("delivery failed") !== -1) { isBounce = true; }
if (subjectLower.indexOf("returned mail") !== -1) { isBounce = true; }

var messageId = item.id || "";
var threadId = item.threadId || "";

return {
  json: {
    skipEmail: isBounce,
    messageId: messageId,
    threadId: threadId,
    sender: sender.toLowerCase(),
    senderName: senderName,
    subject: subject,
    body: body,
    fullText: (subject + " " + body).toLowerCase(),
    receivedAt: new Date().toISOString()
  }
};

var item = $input.item.json;
var fullText = item.fullText;
var sender = item.sender;
var subject = item.subject.toLowerCase();

var salesKw = ["buy","purchase","order","pricing","price","quote","quotation",
  "discount","deal","offer","proposal","contract","subscription",
  "upgrade","demo","trial","wholesale","retail","partnership",
  "promotion","catalog","negotiate","bid"];
var salesSender = ["sales@","partner@","vendor@","business@"];
var salesSubject = ["order","quote","pricing","proposal","deal","purchase"];

var csKw = ["complaint","issue","problem","broken","defective","return",
  "refund","exchange","help","support","damaged","warranty",
  "feedback","disappointed","unhappy","frustrated","resolve",
  "escalate","ticket","tracking","assistance"];
var csSender = ["support@","help@","customer@","service@"];
var csSubject = ["complaint","issue","help","support","return","refund"];

var hrKw = ["job","resume","cv","interview","hiring","recruit","vacancy",
  "application","candidate","onboarding","employee","payroll",
  "leave","vacation","benefits","insurance","termination",
  "resignation","training","internship","salary","compensation",
  "workplace","attendance","career"];
var hrSender = ["hr@","careers@","recruiting@","jobs@","talent@"];
var hrSubject = ["job","application","resume","interview","hiring","leave","employee"];

var finKw = ["invoice","payment","billing","account","tax","budget",
  "expense","reimbursement","receipt","financial","audit",
  "profit","loss","balance","ledger","accounting","payable",
  "receivable","credit","debit","bank","transfer","fiscal",
  "expenditure","procurement"];
var finSender = ["finance@","billing@","accounts@","accounting@","payable@"];
var finSubject = ["invoice","payment","billing","budget","expense","tax","financial"];

var opsKw = ["logistics","shipping","warehouse","inventory",
  "delivery","dispatch","fleet","maintenance","equipment",
  "facility","production","manufacturing","safety","compliance",
  "regulation","inspection","schedule","shift","operations",
  "stock","fulfillment","distribution","transport","freight"];
var opsSender = ["ops@","operations@","logistics@","warehouse@","shipping@"];
var opsSubject = ["shipping","delivery","inventory","maintenance","logistics","warehouse"];

function scoreList(text, list) {
  var s = 0;
  var m = [];
  for (var i = 0; i < list.length; i++) {
    if (text.indexOf(list[i]) !== -1) { s = s + 1; m.push(list[i]); }
  }
  return { score: s, matched: m };
}

function scoreSender(addr, patterns) {
  var s = 0;
  var m = [];
  for (var i = 0; i < patterns.length; i++) {
    if (addr.indexOf(patterns[i]) !== -1) { s = s + 3; m.push(patterns[i]); }
  }
  return { score: s, matched: m };
}

function scoreSubject(subj, patterns) {
  var s = 0;
  var m = [];
  for (var i = 0; i < patterns.length; i++) {
    if (subj.indexOf(patterns[i]) !== -1) { s = s + 2; m.push(patterns[i]); }
  }
  return { score: s, matched: m };
}

var departments = [
  { name: "Sales", kw: salesKw, sp: salesSender, su: salesSubject },
  { name: "Customer Service", kw: csKw, sp: csSender, su: csSubject },
  { name: "Human Resources", kw: hrKw, sp: hrSender, su: hrSubject },
  { name: "Finance", kw: finKw, sp: finSender, su: finSubject },
  { name: "Operations", kw: opsKw, sp: opsSender, su: opsSubject }
];

var scores = {};
var allMatched = {};
var maxScore = 0;
var bestDept = "Unknown";

for (var d = 0; d < departments.length; d++) {
  var dept = departments[d];
  var kwR = scoreList(fullText, dept.kw);
  var spR = scoreSender(sender, dept.sp);
  var suR = scoreSubject(subject, dept.su);
  var total = kwR.score + spR.score + suR.score;
  scores[dept.name] = total;
  allMatched[dept.name] = kwR.matched.concat(spR.matched).concat(suR.matched);
  if (total > maxScore) { maxScore = total; bestDept = dept.name; }
}

var totalAll = 0;
for (var key in scores) { totalAll = totalAll + scores[key]; }
var confidence = 0;
if (totalAll > 0) { confidence = Math.round((maxScore / totalAll) * 100); }

var needsAI = (maxScore < 3) || (confidence < 50);

return {
  json: {
    messageId: item.messageId,
    threadId: item.threadId,
    sender: item.sender,
    senderName: item.senderName,
    subject: item.subject,
    body: item.body,
    fullText: item.fullText,
    receivedAt: item.receivedAt,
    ruleResult: {
      department: maxScore > 0 ? bestDept : "Unknown",
      confidence: confidence,
      maxScore: maxScore,
      scores: scores,
      matched: allMatched[bestDept] || [],
      needsAI: needsAI
    }
  }
};

var item = $input.item.json;

var prompt = "Classify this email into EXACTLY ONE department.\n\n";
prompt += "Departments:\n";
prompt += "1. Sales - buying, purchasing, pricing, quotes, orders, deals, proposals\n";
prompt += "2. Customer Service - complaints, issues, refunds, returns, support\n";
prompt += "3. Human Resources - jobs, resumes, interviews, hiring, leave, salary\n";
prompt += "4. Finance - invoices, payments, billing, budgets, expenses, tax\n";
prompt += "5. Operations - shipping, logistics, warehouse, inventory, maintenance\n";
prompt += "6. Other - does not fit any department above\n\n";
prompt += "EMAIL:\n";
prompt += "From: " + item.sender + "\n";
prompt += "Subject: " + item.subject + "\n";
prompt += "Body: " + item.body.substring(0, 2000) + "\n\n";
prompt += "RESPOND WITH ONLY THIS JSON AND NOTHING ELSE:\n";
prompt += '{"department":"DEPARTMENT_NAME","confidence":85,"reason":"brief explanation"}';

return {
  json: {
    messageId: item.messageId,
    threadId: item.threadId,
    sender: item.sender,
    senderName: item.senderName,
    subject: item.subject,
    body: item.body,
    receivedAt: item.receivedAt,
    groqBody: {
      model: "llama-3.1-8b-instant",
      messages: [
        {
          role: "user",
          content: prompt
        }
      ],
      temperature: 0.1,
      max_tokens: 150
    }
  }
};

var item = $input.item.json;
var department = "Other";
var confidence = 0;
var reason = "Could not parse response";

try {
  var rawText = "";

  if (item.choices && item.choices[0] && item.choices[0].message) {
    rawText = item.choices[0].message.content || "";
  }

  rawText = rawText.replace(/```json/g, "");
  rawText = rawText.replace(/```/g, "");
  rawText = rawText.trim();

  var parsed = JSON.parse(rawText);
  department = parsed.department || "Other";
  confidence = parsed.confidence || 0;
  reason = parsed.reason || "";
} catch (e) {
  department = "Other";
  confidence = 0;
  reason = "Parse error";
}

var validDepts = ["Sales","Customer Service","Human Resources","Finance","Operations","Other"];
var isValid = false;
for (var i = 0; i < validDepts.length; i++) {
  if (validDepts[i] === department) { isValid = true; }
}
if (!isValid) { department = "Other"; }

// FIXED: Pull original email data from the Build AI Request node
var buildNode = $("Build AI Request").item.json;

return {
  json: {
    messageId: buildNode.messageId || "",
    threadId: buildNode.threadId || "",
    sender: buildNode.sender || "",
    senderName: buildNode.senderName || "",
    subject: buildNode.subject || "",
    body: buildNode.body || "",
    receivedAt: buildNode.receivedAt || "",
    classification: {
      department: department,
      confidence: confidence,
      method: "AI (Groq - Llama 3.1)",
      reason: reason
    }
  }
};

var item = $input.item.json;

return {
  json: {
    messageId: item.messageId,
    threadId: item.threadId,
    sender: item.sender,
    senderName: item.senderName,
    subject: item.subject,
    body: item.body,
    receivedAt: item.receivedAt,
    classification: {
      department: item.ruleResult.department,
      confidence: item.ruleResult.confidence,
      method: "Rule-Based (Keywords)",
      reason: "Matched: " + item.ruleResult.matched.join(", ")
    }
  }
};

